#!/usr/bin/env python3
"""
CCI — 只做多版本

CCI < -100（超卖）时做多，CCI > 100 时平仓（HOLD，不做空）。
适合牛市 / 震荡上行行情。
"""

from typing import Dict, List, Optional
from core.strategy import Strategy, Signal, TradingSignal
from core.strategy.strategy_cci import CCI as _Base, CCIConfig


class CCILong(Strategy):
    """CCI — Long Only"""

    def __init__(self, exchange=None, config: Optional[CCIConfig] = None):
        self.exchange = exchange
        self._base = _Base(exchange, config)

    @property
    def name(self) -> str:
        return "cci_long"

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        sig = self._base.generate_signal(coin, klines)
        if sig.signal == Signal.SELL:
            return TradingSignal(
                signal=Signal.HOLD, confidence=sig.confidence, coin=coin,
                timestamp=sig.timestamp, metadata=sig.metadata)
        return sig

